    "coverImage": "https://images.unsplash.com/photo-1629904853716-f0bc54eea481?ixid=M3w4MzY0NTR8MHwxfHNlYXJjaHwzfHxBSSUyMGNvZGUlMjBnZW5lcmF0aW9uJTJDJTIwc29mdHdhcmUlMjBhcmNoaXRlY3R1cmUlMkMlMjBkZXZlbG9wZXJzJTIwcmV2aWV3aW5nJTIwY29kZSUyQyUyMGFic3RyYWN0JTIwdGVjaG5vbG9neXxlbnwwfDB8fHwxNzgzOTc2MjEyfDA&ixlib=rb-4.1.0&w=800&h=400&fit=crop",
