// src/lib/mcp/tools/list-posts.ts
var list_posts_default = defineTool({
  name: "list_posts",
  title: "List blog posts",
  description: "List all blog posts on Volodymyr Shcherbyna's blog with their slug, title, date, category, excerpt, and tags. Use this to discover posts before calling get_post.",
  inputSchema: {
    limit: z.number().int().positive().optional().describe("Optional maximum number of posts to return (most recent first)."),
    tag: z.string().optional().describe("Optional case-insensitive tag filter.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ limit, tag }) => {
    const filtered = tag ? posts.filter((p) => p.tags.some((t) => t.toLowerCase() === tag.toLowerCase())) : posts;
    const sorted = [...filtered].sort((a, b) => a.date < b.date ? 1 : -1);
    const items = (limit ? sorted.slice(0, limit) : sorted).map((p) => ({
      slug: p.slug,
      title: p.title,
      date: p.date,
      author: p.author,
      category: p.category,
      excerpt: p.excerpt,
      tags: p.tags,
      readingTime: p.readingTime,
      url: `https://blog.shcherbyna.me/${p.slug}`
    }));
    return {
      content: [{ type: "text", text: JSON.stringify(items, null, 2) }],
      structuredContent: { posts: items, total: items.length }
    };
  }
});

// src/lib/mcp/tools/get-post.ts
import { defineTool as defineTool2 } from "npm:@lovable.dev/mcp-js@0.24.0";
import { z as z2 } from "npm:zod@^3.25.76";
var get_post_default = defineTool2({
  name: "get_post",
  title: "Get blog post",
  description: "Fetch the full markdown content and metadata of a single blog post by its slug. Use list_posts first if you don't know the slug.",
  inputSchema: {
    slug: z2.string().min(1).describe("The post slug, e.g. 'local-mcp-bridge'.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ slug }) => {
    const post = posts.find((p) => p.slug === slug);
    if (!post) {
      return {
        content: [{ type: "text", text: `No post found with slug '${slug}'.` }],
        isError: true
      };
    }
    const payload = {
      slug: post.slug,
      title: post.title,
      date: post.date,
      author: post.author,
      category: post.category,
      excerpt: post.excerpt,
      tags: post.tags,
      readingTime: post.readingTime,
      url: `https://blog.shcherbyna.me/${post.slug}`,
      content: post.content
    };
    return {
      content: [{ type: "text", text: payload.content }],
      structuredContent: payload
    };
  }
});

// src/lib/mcp/tools/search-posts.ts
import { defineTool as defineTool3 } from "npm:@lovable.dev/mcp-js@0.24.0";
import { z as z3 } from "npm:zod@^3.25.76";
var search_posts_default = defineTool3({
  name: "search_posts",
  title: "Search blog posts",
  description: "Full-text search across blog post titles, excerpts, tags, and body content. Returns matching posts ranked by relevance with a short snippet.",
  inputSchema: {
    query: z3.string().min(1).describe("Search phrase or keywords."),
    limit: z3.number().int().positive().max(20).optional().describe("Max results (default 5).")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ query, limit }) => {
    const q = query.toLowerCase();
    const scored = posts.map((p) => {
      const title = p.title.toLowerCase();
      const excerpt = p.excerpt.toLowerCase();
      const tags = p.tags.join(" ").toLowerCase();
      const content = p.content.toLowerCase();
      let score = 0;
      if (title.includes(q)) score += 10;
      if (excerpt.includes(q)) score += 5;
      if (tags.includes(q)) score += 4;
      const contentHits = content.split(q).length - 1;
      score += contentHits;
      const idx = content.indexOf(q);
      const snippet = idx >= 0 ? p.content.slice(Math.max(0, idx - 60), idx + q.length + 120).replace(/\s+/g, " ").trim() : p.excerpt;
      return { post: p, score, snippet };
    }).filter((r) => r.score > 0).sort((a, b) => b.score - a.score).slice(0, limit ?? 5).map((r) => ({
      slug: r.post.slug,
      title: r.post.title,
      date: r.post.date,
      excerpt: r.post.excerpt,
      tags: r.post.tags,
      snippet: r.snippet,
      url: `https://blog.shcherbyna.me/${r.post.slug}`
    }));
    return {
      content: [{ type: "text", text: JSON.stringify(scored, null, 2) }],
      structuredContent: { results: scored, total: scored.length }
    };
  }
});

// src/lib/mcp/index.ts
var mcp_default = defineMcp({
  name: "shcherbyna-blog-mcp",
  title: "Volodymyr Shcherbyna's Blog",
  version: "0.1.0",
  instructions: "Public read-only tools for Volodymyr Shcherbyna's blog (blog.shcherbyna.me). Use `list_posts` to browse posts, `search_posts` to search across titles/content/tags, and `get_post` to fetch full markdown content of a single post by slug.",
  tools: [list_posts_default, get_post_default, search_posts_default]
});

